final:
module top_module(sin, sout);input wire [3:0] sin;
output wire [6:0] sout;
reg [6:0] obf_SEG_buf;

  always @ (sin)
  begin
    case(sin)
      4'h0: obf_SEG_buf <= 7'b0111111;
      4'h1: obf_SEG_buf <= 7'b0000110;
      4'h2: obf_SEG_buf <= 7'b1011011;
      4'h3: obf_SEG_buf <= 7'b1001111;
      4'h4: obf_SEG_buf <= 7'b1100110;
      4'h5: obf_SEG_buf <= 7'b1101101;
      4'h6: obf_SEG_buf <= 7'b1111101;
      4'h7: obf_SEG_buf <= 7'b0000111;
      4'h8: obf_SEG_buf <= 7'b1111111;
      4'h9: obf_SEG_buf <= 7'b1101111;
      default: obf_SEG_buf <= 7'b0000000;
    endcase
  end 

  assign sout = obf_SEG_buf;

endmodule
